using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Services; namespace SchoolEnterprise.Repositories; public class SubjectRepository(XmlStorageService storage) : BaseXmlRepository<Subject>(storage){ protected override string FileName=>"subjects.xml"; public Subject? GetById(int id)=>GetAll().FirstOrDefault(x=>x.SubjectId==id); public void Add(Subject i){var a=GetAll();a.Add(i);SaveAll(a);} public void Update(Subject i){var a=GetAll();var x=a.FindIndex(t=>t.SubjectId==i.SubjectId);if(x>=0){a[x]=i;SaveAll(a);}} public void Delete(int id){var a=GetAll();a.RemoveAll(x=>x.SubjectId==id);SaveAll(a);} }
